 73→fn build_context_groups(
 74→    actions: &[NextAction],
 75→    contexts: &[Context],
 76→    single_context: bool,
 77→) -> Vec<ContextGroup> {
 78→    if single_context {
 79→        // When filtering by a single context, put all actions in one group
 80→        // (the heading is redundant since the filter pill already shows it)
 81→        let context_name = actions
 82→            .first()
 83→            .and_then(|a| {
 84→                contexts
 85→                    .iter()
 86→                    .find(|c| c.id() == a.context_id())
 87→                    .map(|c| c.name().as_str().to_string())
 88→            })
 89→            .unwrap_or_default();
 90→
 91→        let context_id = actions
 92→            .first()
 93→            .map(|a| a.context_id().as_uuid().to_string())
 94→            .unwrap_or_default();
 95→
 96→        let action_views = actions
 97→            .iter()
 98→            .map(|a| build_action_view(a, contexts))
 99→            .collect();
100→
101→        return vec![ContextGroup {
102→            context_name,
103→            context_id,
104→            actions: action_views,
105→        }];
106→    }
107→
108→    // "All" view: group actions by context, preserving context order
109→    let mut groups: Vec<ContextGroup> = Vec::new();
110→
111→    for ctx in contexts {
112→        let ctx_actions: Vec<NextActionView> = actions
113→            .iter()
114→            .filter(|a| a.context_id() == ctx.id())
115→            .map(|a| build_action_view(a, contexts))
116→            .collect();
117→
118→        if !ctx_actions.is_empty() {
119→            groups.push(ContextGroup {
120→                context_name: ctx.name().as_str().to_string(),
121→                context_id: ctx.id().as_uuid().to_string(),
122→                actions: ctx_actions,
123→            });
124→        }
125→    }
126→
127→    groups
128→}
