fn build_context_groups(
    actions: &[NextAction],
    contexts: &[Context],
    single_context: bool,
) -> Vec<ContextGroup> {
    if single_context {
        // When filtering by a single context, put all actions in one group
        // (the heading is redundant since the filter pill already shows it)
        let context_name = actions
            .first()
            .and_then(|a| {
